script:
frappe.after_ajax(() => {
    const tableroot = root_element.querySelector('#number-card-table-root');
    setTimeout(() => {
        bind_number_card_clicks();
        apply_number_card_colors();

        load_number_card_table("Cash Balance", tableroot);
    }, 600);
});

let __cached_table_data = null;
let __active_card_name = null;

const cardColorMap = {
    "Cash Balance": "orange",
    "Bank Balance": "red",
    "Open Quotation": "green",
    "Customer To Delivery": "grey"
};

/* 
   Listen for global company change
 */
window.addEventListener("nextlayer_company_changed", e => {
    const company = e.detail.company;
    refresh_number_cards()
    // Only reload table if a card is active
    if (!__active_card_name) return;

    const tableRoot = root_element.querySelector("#number-card-table-root");
    if (!tableRoot) return;

    load_number_card_table(__active_card_name, tableRoot);
});


function refresh_number_cards() {
    const company = window.nextlayer_dashboard?.selected_company
        || frappe.defaults.get_user_default("Company");

    const cards = document.querySelectorAll('div[number_card_name]');
    cards.forEach(card => {
        const cardName = card.getAttribute("number_card_name");

        // Correctly select the .number element
        const widgetNumber = card.querySelector(".widget-content .number");
        if (!widgetNumber) return;



        if (cardName === "Cash Balance") {
            frappe.call({
                method: "nextlayer.next_layer.number_card.cash_balance.get_cash_balance.get_cash_balance",
                args: { company },
                callback: r => {
                    if (!r.message || !r.message.length) {
                        widgetNumber.textContent = "No data";
                        return;
                    }
                    const total = r.message.reduce((acc, a) => acc + (a.Balance || a["Total Balance"] || 0), 0);
                    const formatted = frappe.format(total, { fieldtype: "Currency" });
                    const tempDiv = document.createElement("div");
                    tempDiv.innerHTML = formatted;
                    const plainText = tempDiv.textContent || tempDiv.innerText || "";
                    widgetNumber.textContent = plainText;
                }
            });
        }

        if (cardName === "Bank Balance") {
            frappe.call({
                method: "nextlayer.next_layer.number_card.bank_balance_1.get_bank_balance.get_accounts_balance",
                args: { company },
                callback: r => {
                    if (!r.message || !r.message.length) {
                        widgetNumber.textContent = "No data";
                        return;
                    }
                    const total = r.message.reduce((acc, a) => acc + (a.Balance || a["Total Balance"] || 0), 0);
                    const formatted = frappe.format(total, { fieldtype: "Currency" });
                    const tempDiv = document.createElement("div");
                    tempDiv.innerHTML = formatted;
                    const plainText = tempDiv.textContent || tempDiv.innerText || "";
                    widgetNumber.textContent = plainText;
                }


            });
        }

        if (cardName === "Customer To Delivery") {
            frappe.call({
                method: "nextlayer.next_layer.number_card.customer_to_delivery.customer_to_delivery.get_customer_to_delivery_count",
                args: { company },
                callback: r => {
                    if (!r.message) {
                        widgetNumber.textContent = "No data";
                        return;
                    }

                    // Use frappe.format if you want, but strip HTML
                    const plainText = formatPlainText(r.message.value, { fieldtype: r.message.fieldtype })
                    widgetNumber.textContent = plainText;
                }
            });
        }

        if (cardName === "Open Quotation") {
            frappe.call({
                method: "nextlayer.next_layer.number_card.open_quotation.open_quotation.get_open_quotation_count",
                args: { company },
                callback: r => {
                    if (!r.message) {
                        widgetNumber.textContent = "No data";
                        return;
                    }

                    // Use frappe.format if you want, but strip HTML

                    const plainText = r.message.value
                    widgetNumber.textContent = plainText;
                }
            });
        }



    });
}

function formatPlainText(value, options = {"fieldtype": "Currency"}) {
    const formatted = frappe.format(value, options);
    const tempDiv = document.createElement("div");
    tempDiv.innerHTML = formatted;
    const plainText = tempDiv.textContent || tempDiv.innerText || "";
    return plainText;
}


/* 
   Number card clicks
 */
function bind_number_card_clicks() {
    const blocks = document.querySelectorAll('.ce-block div[number_card_name]');
    const tableRoot = root_element.querySelector('#number-card-table-root');
    if (!tableRoot) return;

    if (!tableRoot.querySelector(".table-container")) {
        const div = document.createElement("div");
        div.className = "table-container";
        tableRoot.appendChild(div);
    }

    blocks.forEach(wrapper => {
        const cardName = wrapper.getAttribute("number_card_name");
        if (!cardName) return;

        const ceBlock = wrapper.closest(".ce-block");
        if (!ceBlock) return;

        ceBlock.style.cursor = "pointer";

        const widget = wrapper.querySelector('.number-widget-box');
        if (!widget) return;

        widget.addEventListener("mousedown", e => e.stopImmediatePropagation(), true);

        widget.addEventListener("click", e => {
            e.preventDefault();
            e.stopImmediatePropagation();
            load_number_card_table(cardName, tableRoot);
        }, true);
    });
}

/* 
   Load table
 */
function load_number_card_table(cardName, tableRoot) {
    __active_card_name = cardName;

    const tableContainer = tableRoot.querySelector(".table-container");
    tableContainer.innerHTML = `<p class="text-muted">Loading ${cardName}…</p>`;

    // Use currently selected company
    const selected_company = window.nextlayer_dashboard?.selected_company
        || frappe.defaults.get_user_default("Company");

    /*  Customer To Delivery  */
    if (cardName === "Customer To Delivery") {
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Sales Order",
                filters: {
                    company: selected_company,
                    docstatus: 1,
                    status: ["in", ["To Deliver", "To Deliver and Bill", "To Bill"]]
                },
                fields: [
                    "name", "customer", "customer_name", "transaction_date",
                    "delivery_date", "grand_total", "status", "per_delivered"
                ],
                order_by: "delivery_date asc, transaction_date asc",
                limit_page_length: 1000
            },
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }

                frappe.db.get_value("Company", selected_company, "default_currency").then(currency_result => {
                    const currency = currency_result ? currency_result.default_currency : "";
                    const formattedData = r.message.map(so => ({
                        "Sales Order ID": so.name,
                        "Customer": so.customer_name || so.customer,
                        "Order Date": so.transaction_date || "",
                        "Delivery Date": so.delivery_date || "",
                        "Amount": formatPlainText(so.grand_total),
                        "Status": so.status,
                        "Delivered %": (so.per_delivered || 0) + "%"
                    }));

                    __cached_table_data = formattedData;
                    inject_filters(tableRoot);
                    render_table(tableRoot, formattedData, cardName);
                    bind_sales_order_links(tableRoot);
                });
            }
        });
        return;
    }

    /*  Cash Balance  */
    if (cardName === "Cash Balance") {
        frappe.call({
            method: "nextlayer.next_layer.number_card.cash_balance.get_cash_balance.get_cash_balance",
            args: { company: selected_company },
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }

                const formattedData = r.message.map(acc => ({
                    "Account": acc.Account || acc["Account Type"] || "",
                    "Balance": formatPlainText(acc.Balance || acc["Total Balance"] || 0)
                }));

                __cached_table_data = formattedData;
                inject_filters(tableRoot);
                render_table(tableRoot, formattedData, cardName);
            }
        });
        return;
    }

    /*  Bank Balance  */
    if (cardName === "Bank Balance") {
        frappe.call({
            method: "nextlayer.next_layer.number_card.bank_balance_1.get_bank_balance.get_accounts_balance",
            args: { company: selected_company },
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }

                const formattedData = r.message.map(acc => ({
                    "Account": acc.Account || acc["Account Type"] || "",
                    "Balance": formatPlainText(acc.Balance || acc["Total Balance"] || 0)
                }));

                __cached_table_data = formattedData;
                inject_filters(tableRoot);
                render_table(tableRoot, formattedData, cardName);
            }
        });
        return;
    }

    /*  Open Quotation  */
    if (cardName === "Open Quotation") {
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Quotation",
                filters: { company: selected_company, docstatus: 1, status: "Open" },
                fields: [
                    "name", "party_name", "customer_name", "transaction_date",
                    "valid_till", "grand_total", "status"
                ],
                order_by: "transaction_date desc",
                limit_page_length: 1000
            },
            callback: r => {
                if (!r.message || !r.message.length) {
                    tableContainer.innerHTML = `<p class="text-muted">No data</p>`;
                    return;
                }

                frappe.db.get_value("Company", selected_company, "default_currency").then(currency_result => {
                    const currency = currency_result ? currency_result.default_currency : "";
                    const formattedData = r.message.map(q => ({
                        "Quotation ID": q.name,
                        "Customer": q.customer_name || q.party_name || "",
                        "Date": q.transaction_date || "",
                        "Valid Till": q.valid_till || "",
                        "Amount": formatPlainText(q.grand_total),
                        "Status": q.status
                    }));

                    __cached_table_data = formattedData;
                    inject_filters(tableRoot);
                    render_table(tableRoot, formattedData, cardName);
                });
            }
        });
        return;
    }

    tableContainer.innerHTML = `<p class="text-muted">No API mapped for ${cardName}</p>`;
}

/* Table renderer with cleaner style */
function render_table(tableRoot, data, cardName) {
    const tableContainer = tableRoot.querySelector(".table-container");

    if (!data.length) {
        tableContainer.innerHTML = `<p class="text-muted">No matching results</p>`;
        return;
    }

    const dataColumns = Object.keys(data[0]);
    const columns = ["#", ...dataColumns];

    const thColor = cardColorMap[cardName] || "#ddd";

    const thead = `
        <thead>
            <tr>
                ${columns.map(c => `<th style="background-color:${thColor}; color:white;">${c}</th>`).join("")}
            </tr>
        </thead>
    `;

    const tbody = `
        <tbody>
            ${data.map((row, idx) => `
                <tr>
                    <td>${idx + 1}</td>
                    ${dataColumns.map(c => {
                        if (cardName === "Customer To Delivery" && c === "Sales Order ID") {
                            return `<td><a href="#" class="so-link" data-so="${row[c]}">${row[c]}</a></td>`;
                        }
                        return `<td>${row[c] ?? ""}</td>`;
                    }).join("")}
                </tr>
            `).join("")}
        </tbody>
    `;

    tableContainer.innerHTML = `<table class="table table-sm table-striped">${thead}${tbody}</table>`;
}

/* Filter UI and logic: only for Customer To Delivery */
function inject_filters(tableRoot) {
    let filterBar = tableRoot.querySelector(".filter-bar");

    if (!filterBar) {
        filterBar = document.createElement("div");
        filterBar.className = "filter-bar mb-2 gap-2";
        filterBar.innerHTML = `
         <div class="form-group form-group-sm ms-2" style="margin-right: 5px; width: 22%">
        <label for="filter-sales-order" class="form-label">Sales Order ID:</label>
        <input id="filter-sales-order" type="text" class="form-control form-control-sm" data-filter="sales_order">
    </div>
    <div class="form-group form-group-sm" style="margin-right: 5px; width: 22%">
        <label for="filter-customer" class="form-label">Customer:</label>
        <input id="filter-customer" type="text" class="form-control form-control-sm" data-filter="customer">
    </div>

    <div class="form-group form-group-sm ms-2" style="margin-right: 5px; width: 22%">
        <label for="filter-order-date" class="form-label">Order Date:</label>
        <input id="filter-order-date" type="date" class="form-control form-control-sm" data-filter="order_date">
    </div>

    <div class="form-group form-group-sm ms-2" style="margin-right: 5px; width: 22%">
        <label for="filter-delivery-date" class="form-label">Delivery Date:</label>
        <input id="filter-delivery-date" type="date" class="form-control form-control-sm" data-filter="delivery_date">
    </div>

`;
        tableRoot.prepend(filterBar);

        const keyMap = {
            customer: "Customer",
            sales_order: "Sales Order ID",
            order_date: "Order Date",
            delivery_date: "Delivery Date"
        };

        filterBar.querySelectorAll("input").forEach(input => {
            input.addEventListener("input", e => {
                e.stopImmediatePropagation();
                apply_filters(tableRoot, keyMap);
            });

            ["keydown", "keypress", "keyup", "mousedown", "focus"].forEach(evt =>
                input.addEventListener(evt, e => e.stopImmediatePropagation(), true)
            );
        });
    }

    // Show filter only for Customer To Delivery
    filterBar.style.display = (__active_card_name === "Customer To Delivery") ? "flex" : "none";
}

/* Apply filters including exact date match */
function apply_filters(tableRoot, keyMap) {
    if (!__cached_table_data) return;

    const inputs = tableRoot.querySelectorAll(".filter-bar input");
    let filtered = [...__cached_table_data];

    inputs.forEach(input => {
        const key = keyMap[input.dataset.filter];
        const value = input.value;

        if (!value) return;

        if (input.dataset.filter === "order_date" || input.dataset.filter === "delivery_date") {
            filtered = filtered.filter(row => row[key] === value);
            return;
        }

        filtered = filtered.filter(row =>
            String(row[key] || "").toLowerCase().includes(value.toLowerCase())
        );
    });

    render_table(tableRoot, filtered, __active_card_name);
    bind_sales_order_links(tableRoot);
}

/* Sales Order → Invoice */
function bind_sales_order_links(tableRoot) {
    tableRoot.querySelectorAll(".so-link").forEach(link => {
        link.addEventListener("click", e => {
            e.preventDefault();
            e.stopImmediatePropagation();
            const so = link.dataset.so;

            frappe.model.open_mapped_doc({
                method: "erpnext.selling.doctype.sales_order.sales_order.make_sales_invoice",
                source_name: so
            });
        });
    });
}

/* Number card colors */
function apply_number_card_colors() {
    const cards = document.querySelectorAll('div[number_card_name]');
    cards.forEach(card => {
        const cardName = card.getAttribute("number_card_name");
        const color = cardColorMap[cardName];
        if (!color) return;

        if (card.querySelector(".number-card-color-bar")) return;

        const bar = document.createElement("div");
        bar.className = "number-card-color-bar";
        Object.assign(bar.style, {
            position: "absolute",
            left: "0",
            top: "0",
            width: "4%",
            height: "100%",
            backgroundColor: color,
            borderRadius: "12px 0 0 12px",
            zIndex: "10"
        });

        const widgetBox = card.querySelector(".number-widget-box");
        if (widgetBox) {
            widgetBox.style.position = "relative";
            widgetBox.prepend(bar);
        }
    });
}

