script:
frappe.after_ajax(() => {
    setTimeout(() => {
        populate_company_filter();
    }, 600);
});

window.nextlayer_dashboard = window.nextlayer_dashboard || {};

function populate_company_filter() {
    const select = root_element.querySelector("#company-filter-select");
    if (!select) return;

    // Prevent double population
    if (select.dataset.loaded) return;
    select.dataset.loaded = "1";

    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Company",
            fields: ["name"],
            order_by: "name asc",
            limit_page_length: 100
        },
        callback: function (r) {
            if (!r.message) return;

            // Clear existing options (safety)
            select.innerHTML = "";

            r.message.forEach(company => {
                const opt = document.createElement("option");
                opt.value = company.name;
                opt.textContent = company.name;
                select.appendChild(opt);
            });

            // Set default company
            const default_company = frappe.defaults.get_user_default("Company");
            if (default_company) {
                select.value = default_company;
                window.nextlayer_dashboard.selected_company = default_company;
            } else {
                window.nextlayer_dashboard.selected_company = select.value;
            }

            // Bind change event AFTER population
            bind_company_change(select);
        }
    });
}

function bind_company_change(select) {
    select.addEventListener("change", e => {
        const company = e.target.value;

        // Update global variable
        window.nextlayer_dashboard.selected_company = company;

        // Notify other Custom HTML blocks
        window.dispatchEvent(
            new CustomEvent("nextlayer_company_changed", {
                detail: { company }
            })
        );
    });
}
